min_len = min(len(vllm_completion_logprobs), len(vllm_rollout_logps))
comp_vllm_logps = np.array(vllm_completion_logprobs[:min_len])
comp_rollout_logps = np.array(vllm_rollout_logps[:min_len])

rollout_diff = np.abs(comp_vllm_logps - comp_rollout_logps)
rollout_diff_mean = np.mean(rollout_diff)
