masked_diff = diff * completion_mask

diff_mean = jnp.sum(masked_diff) / jnp.sum(completion_mask)
diff_std = jnp.sqrt(jnp.sum(jnp.square(diff) * completion_mask) / jnp.sum(completion_mask))

